class OctreeNode {
  constructor(bounds, maxObjects = 8, maxLevels = 5) {
    this.bounds = bounds;
    this.objects = [];
    this.children = null;
    this.level = 0;
  }

  subdivide() {
    // Split into 8 child nodes
    const subWidth = this.bounds.width / 2;
    this.children = [
      new OctreeNode(/* 8 subdivisions */),
      // ... 7 more children
    ];
  }

  insert(object) {
    if (this.children) {
      const index = this.getChildIndex(object);
      this.children[index].insert(object);
    } else {
      this.objects.push(object);
      if (this.objects.length > this.maxObjects) {
        this.subdivide();
      }
    }
  }
}
```

