class Command {
  execute() { /* override */ }
  undo() { /* override */ }
  serialize() { /* override */ }
}

class MoveObjectCommand extends Command {
  constructor(object, oldPos, newPos) {
    this.object = object;
    this.oldPos = oldPos;
    this.newPos = newPos;
  }

  execute() {
    this.object.position = this.newPos;
  }

  undo() {
    this.object.position = this.oldPos;
  }

  serialize() {
    return {
      type: 'move',
      id: this.object.id,
      delta: this.newPos.subtract(this.oldPos)
    };
  }
}
```

