class PresenceManager {
  constructor(userId) {
    this.userId = userId;
    this.state = 'online';
    this.lastActivity = Date.now();
    this.heartbeatInterval = null;
  }

  startHeartbeat() {
    this.heartbeatInterval = setInterval(() => {
      this.sendHeartbeat();
      this.updateState();
    }, 30000); // 30 seconds
  }

  updateState() {
    const idle = Date.now() - this.lastActivity;
    if (idle > 300000) { // 5 min
      this.setState('away');
    } else if (idle > 60000) { // 1 min
      this.setState('idle');
    } else {
      this.setState('online');
    }
  }

  onActivity() {
    this.lastActivity = Date.now();
    this.updateState();
  }
}
```

