class HapticEngine {
  constructor() {
    this.patterns = {
      click: { duration: 10, intensity: 0.5 },
      success: { duration: 50, intensity: 0.7, pattern: [1,0,1] },
      error: { duration: 100, intensity: 1.0, pattern: [1,1,0,1] },
      warning: { duration: 200, intensity: 0.8, pattern: [1,0,1,0,1] }
    };
  }

  trigger(patternName) {
    const pattern = this.patterns[patternName];
    if (!pattern) return;

    if (this.isIOS()) {
      this.triggerIOSHaptic(pattern);
    } else if (this.isAndroid()) {
      this.triggerAndroidHaptic(pattern);
    } else if (this.isWeb()) {
      this.triggerWebHaptic(pattern);
    }
  }

  triggerWebHaptic(pattern) {
    if (!navigator.vibrate) return;

    const vibrationPattern = pattern.pattern.map(
      (v, i) => v ? pattern.duration : 50
    );
    navigator.vibrate(vibrationPattern);
  }
}
```

BOTTOM LEFT - Code Example 2:
Monospace font code block with title "Timing Precision":
```javascript
class PrecisionHapticController {
  constructor() {
    this.queue = [];
    this.isPlaying = false;
  }

  scheduleHaptic(pattern, timestamp) {
    this.queue.push({ pattern, timestamp });
    this.queue.sort((a, b) => a.timestamp - b.timestamp);

    if (!this.isPlaying) {
      this.playQueue();
    }
  }

  async playQueue() {
    this.isPlaying = true;

    while (this.queue.length > 0) {
      const next = this.queue[0];
      const now = performance.now();
      const delay = next.timestamp - now;

      if (delay > 0) {
        await this.preciseDelay(delay);
      }

      this.trigger(next.pattern);
      this.queue.shift();
    }

    this.isPlaying = false;
  }
}
```

